import React, { useState, useEffect } from 'react';
import { 
  Briefcase, 
  Target, 
  TrendingUp, 
  AlertTriangle, 
  Users, 
  BrainCircuit, 
  ArrowRight,
  DollarSign,
  Activity,
  Layers,
  Sparkles,
  Zap,
  ShieldAlert,
  Wallet,
  Smartphone,
  BarChart2,
  Search,
  Crosshair,
  Share2,
  Flag,
  FileText
} from 'lucide-react';
import { ClientProfile, ClientStage, InsightResponse } from '../types';
import { TrendChart, CompetitorChart, FunnelChart, DonutChart, MultiLineChart } from './Charts';
import { generateClientInsight } from '../services/geminiService';

interface ClientDetailProps {
  client: ClientProfile;
}

export const ClientDetail: React.FC<ClientDetailProps> = ({ client }) => {
  const [insight, setInsight] = useState<InsightResponse | null>(null);
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [activeTab, setActiveTab] = useState('performance');

  // Reset insight and tab when client changes
  useEffect(() => {
    setInsight(null);
    // Set default tab based on stage
    if (client.stage === ClientStage.PROSPECT) {
      setActiveTab('prospect');
    } else if (client.stage === ClientStage.CHURN) {
      setActiveTab('churn');
    } else {
      setActiveTab('performance');
    }
  }, [client.id]);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
  };

  const renderHeader = () => (
    <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
      <div className="flex items-center gap-4">
        <img src={client.logo} alt={client.name} className="w-16 h-16 rounded-lg object-cover bg-gray-50" />
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{client.name}</h1>
          <div className="flex items-center gap-2 text-sm text-gray-500 mt-1">
            <span className="flex items-center gap-1"><Briefcase size={14} /> {client.industry}</span>
            <span>•</span>
            <span className="flex items-center gap-1"><Layers size={14} /> {client.apps.length} 个应用</span>
          </div>
        </div>
      </div>
      <div className="flex items-center gap-3">
        <span className={`px-4 py-2 rounded-full text-sm font-semibold 
          ${client.stage === ClientStage.ACTIVE ? 'bg-green-100 text-green-700' : 
            client.stage === ClientStage.PROSPECT ? 'bg-blue-100 text-blue-700' : 
            'bg-red-100 text-red-700'}`}>
          {client.stage === ClientStage.PROSPECT && '拓展期 / 潜在客户'}
          {client.stage === ClientStage.ACTIVE && '活跃期 / 投放中'}
          {client.stage === ClientStage.CHURN && '流失期 / 风险客户'}
        </span>
      </div>
    </div>
  );

  const renderEmptyState = (message: string) => (
    <div className="flex flex-col items-center justify-center py-16 bg-white rounded-xl border border-dashed border-gray-300">
      <div className="bg-gray-50 p-4 rounded-full mb-3">
        <FileText className="text-gray-400" size={32} />
      </div>
      <h3 className="text-gray-900 font-medium mb-1">暂无数据</h3>
      <p className="text-gray-500 text-sm">{message}</p>
    </div>
  );

  const renderProspectTab = () => {
    // If we have minimal prospect data or if it's an active client with prospect history
    const steps = ['Lead', 'Contacted', 'Meeting', 'Negotiation', 'Onboarding'];
    const stepLabels = ['线索', '已联系', '会议', '谈判', '入驻'];
    const currentStepIdx = steps.indexOf(client.prospectStage || (client.stage === ClientStage.ACTIVE ? 'Onboarding' : 'Lead'));

    return (
      <div className="space-y-6">
        {/* Pipeline Progress */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-6 flex items-center gap-2">
            <Flag size={18} className="text-blue-600"/> 拓展漏斗与进度
          </h3>
          <div className="relative flex items-center justify-between w-full px-4">
            <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-full h-1 bg-gray-100 -z-10" />
            {stepLabels.map((step, idx) => (
              <div key={step} className="flex flex-col items-center bg-white px-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold mb-2 transition-colors border-2
                  ${idx <= currentStepIdx ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-gray-300 text-gray-400'}`}>
                  {idx + 1}
                </div>
                <span className={`text-xs ${idx === currentStepIdx ? 'font-bold text-blue-600' : 'text-gray-500'}`}>
                  {step}
                </span>
              </div>
            ))}
          </div>

          <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4">
             <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                <div className="text-xs text-gray-500 mb-1">最后联系时间</div>
                <div className="font-medium text-gray-900">{client.lastContactDate || '暂无记录'}</div>
             </div>
             <div className="p-4 bg-gray-50 rounded-lg border border-gray-100">
                <div className="text-xs text-gray-500 mb-1">负责 BD</div>
                <div className="font-medium text-gray-900">{client.bdOwner || '未分配'}</div>
             </div>
             <div className="p-4 bg-blue-50 rounded-lg border border-blue-100">
                <div className="text-xs text-blue-800 mb-1">下一步建议</div>
                <div className="font-medium text-blue-900 text-sm">
                    {client.stage === ClientStage.ACTIVE ? '定期回访，挖掘增量预算' : '安排商务会议讨论具体条款'}
                </div>
             </div>
          </div>
        </div>

        {/* Competitor Intel */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
                <Search size={18} className="text-blue-600"/> 竞品情报
             </h3>
             <div className="flex flex-col md:flex-row gap-6 items-center">
                 <div className="flex-1">
                    <p className="text-gray-600 mb-4 text-sm leading-relaxed">
                    该客户主要在 <strong>{client.competitorPlatforms[0] || '未知平台'}</strong> 投入预算。
                    根据市场情报，其在该平台的平均 CPI 约为 $2.50，日均消耗约 $5,000。
                    我方可以通过提供更优的 ROI 或 $2.10 的试投方案来争取预算份额。
                    </p>
                    <button className="text-blue-600 font-medium text-sm flex items-center gap-1 hover:underline">
                    查看详细竞品分析报告 <ArrowRight size={14} />
                    </button>
                 </div>
                 <div className="w-full md:w-1/3 p-4 bg-gray-50 rounded-lg">
                    <div className="text-xs text-gray-500 mb-2">主要竞品平台</div>
                    <div className="flex flex-wrap gap-2">
                        {client.competitorPlatforms.map(p => (
                            <span key={p} className="px-2 py-1 bg-white border border-gray-200 rounded text-xs text-gray-700">{p}</span>
                        ))}
                    </div>
                 </div>
             </div>
        </div>
      </div>
    );
  };

  const renderPerformanceTab = () => {
    if (!client.spendTrend && !client.conversionMetrics) {
        return renderEmptyState("该客户尚未产生足够的分发数据");
    }

    const budgetProgress = client.annualBudget ? Math.min((client.budgetSpent || 0) / client.annualBudget * 100, 100) : 0;

    return (
        <div className="space-y-6">
            {/* Budget & Top KPI Cards */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                        <Wallet size={18} className="text-indigo-600"/> 预算投入概览
                    </h3>
                    <span className="text-sm font-medium text-gray-600">
                        年度总预算: ${(client.annualBudget || 0).toLocaleString()}
                    </span>
                </div>
                <div className="relative pt-1">
                    <div className="flex mb-2 items-center justify-between">
                        <div>
                        <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-indigo-600 bg-indigo-200">
                            达成进度
                        </span>
                        </div>
                        <div className="text-right">
                        <span className="text-xs font-semibold inline-block text-indigo-600">
                            {budgetProgress.toFixed(1)}% (已消耗 ${(client.budgetSpent || 0).toLocaleString()})
                        </span>
                        </div>
                    </div>
                    <div className="overflow-hidden h-2 mb-4 text-xs flex rounded bg-indigo-100">
                        <div style={{ width: `${budgetProgress}%` }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-indigo-500"></div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">总消耗 (Total Spend)</div>
                    <div className="text-xl font-bold text-gray-900">${(client.totalSpend || 0).toLocaleString()}</div>
                    <div className="text-green-600 text-xs mt-1 flex items-center"><TrendingUp size={10} className="mr-1"/> +12%</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">综合 ROI</div>
                    <div className="text-xl font-bold text-gray-900">{client.roi}x</div>
                    <div className="text-gray-400 text-xs mt-1">目标: 2.0x</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">eCPM</div>
                    <div className="text-xl font-bold text-gray-900">${client.conversionMetrics?.ecpm || 0}</div>
                    <div className="text-gray-400 text-xs mt-1">行业均值: $10.50</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">付费率 (PUR)</div>
                    <div className="text-xl font-bold text-gray-900">{client.conversionMetrics?.payRate || 0}%</div>
                </div>
                <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
                    <div className="text-gray-500 text-xs mb-1">LTV</div>
                    <div className="text-xl font-bold text-gray-900">${client.conversionMetrics?.ltv || 0}</div>
                </div>
            </div>

            {/* App Metrics Trend (Impressions, Downloads, Activations) */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-6">
                    <Activity size={18} className="text-indigo-600"/> 应用数据趋势 (曝光/下载/激活)
                </h3>
                {client.funnelHistory && client.funnelHistory.length > 0 ? (
                    <>
                        <div className="h-64 mb-6">
                            <MultiLineChart 
                                data={client.funnelHistory} 
                                lines={[
                                    { key: 'impressions', color: '#94a3b8', name: '曝光量' },
                                    { key: 'downloads', color: '#6366f1', name: '下载量' },
                                    { key: 'activations', color: '#10b981', name: '激活量' },
                                ]}
                            />
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left border-collapse">
                                <thead className="bg-gray-50 text-gray-500">
                                    <tr>
                                        <th className="px-4 py-2 font-medium">日期</th>
                                        <th className="px-4 py-2 font-medium">曝光量</th>
                                        <th className="px-4 py-2 font-medium">下载量</th>
                                        <th className="px-4 py-2 font-medium">下载率</th>
                                        <th className="px-4 py-2 font-medium">激活量</th>
                                        <th className="px-4 py-2 font-medium">激活率</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100">
                                    {[...client.funnelHistory].reverse().map((row, idx) => (
                                        <tr key={idx} className="hover:bg-gray-50">
                                            <td className="px-4 py-2">{row.date}</td>
                                            <td className="px-4 py-2">{row.impressions.toLocaleString()}</td>
                                            <td className="px-4 py-2">{row.downloads.toLocaleString()}</td>
                                            <td className="px-4 py-2 text-gray-500">{((row.downloads / row.impressions) * 100).toFixed(2)}%</td>
                                            <td className="px-4 py-2 font-semibold text-gray-800">{row.activations.toLocaleString()}</td>
                                            <td className="px-4 py-2 text-gray-500">{((row.activations / row.downloads) * 100).toFixed(1)}%</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </>
                ) : (
                    <div className="py-8 text-center text-gray-400">暂无历史趋势数据</div>
                )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Conversion & Funnel */}
                <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2"><Target size={18} className="text-indigo-600"/> 后端转化漏斗</h3>
                    </div>
                    <div className="grid grid-cols-3 gap-4 mb-6 text-center">
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">次日留存</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.retention1d || 0}%</div>
                        </div>
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">7日留存</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.retention7d || 0}%</div>
                        </div>
                        <div className="bg-gray-50 p-3 rounded-lg">
                            <div className="text-xs text-gray-500">ROAS (IAP/IAA)</div>
                            <div className="text-lg font-semibold text-gray-800">{client.conversionMetrics?.roasIAP || 0} / {client.conversionMetrics?.roasIAA || 0}</div>
                        </div>
                    </div>
                    {client.conversionMetrics?.funnel && (
                        <FunnelChart data={client.conversionMetrics.funnel} />
                    )}
                </div>

                {/* Channel Monitoring */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4">
                        <Share2 size={18} className="text-indigo-600"/> 渠道监控
                    </h3>
                    <div className="h-64">
                        {client.channelDistribution ? (
                            <DonutChart data={client.channelDistribution} />
                        ) : (
                            <div className="flex items-center justify-center h-full text-gray-400 text-sm">暂无渠道数据</div>
                        )}
                    </div>
                    <div className="mt-4 p-3 bg-indigo-50 rounded-lg text-xs text-indigo-800">
                        <strong>分发洞察:</strong> 本平台分发量目前占比最高，建议继续保持优化，同时关注其他三方商店的增长趋势。
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Bidding & Competition */}
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Crosshair size={18} className="text-indigo-600"/> 竞价诊断</h3>

                    <div className="mb-6 flex items-center justify-between bg-indigo-50 p-4 rounded-lg">
                        <div>
                            <div className="text-xs text-indigo-800">竞胜率</div>
                            <div className="text-xl font-bold text-indigo-900">{client.biddingData?.winRate || 0}%</div>
                        </div>
                        <div className="text-right">
                            <div className="text-xs text-indigo-800">行业声量 (SOV)</div>
                            <div className="text-xl font-bold text-indigo-900">{client.biddingData?.sov || 0}%</div>
                        </div>
                    </div>

                    <div className="h-48">
                        <p className="text-xs text-center text-gray-500 mb-2">竞价失败归因</p>
                        {client.biddingData?.lossReasons ? (
                            <DonutChart data={client.biddingData.lossReasons.map(r => ({ name: r.reason, value: r.percentage }))} />
                        ) : <div className="text-center text-gray-300 text-xs py-10">暂无数据</div>}
                    </div>
                </div>

                {/* Spend Trend */}
                <div className="lg:col-span-2 bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 mb-4">消耗趋势</h3>
                    <TrendChart data={client.spendTrend || []} dataKey="spend" color="#6366f1" showForecast={true} />
                </div>
            </div>
        </div>
    );
  };

  const renderCreativeProductTab = () => {
    if (!client.creativeStats) {
        return renderEmptyState("暂无素材或产品分析数据");
    }
    return (
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Creative DNA */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Sparkles size={18} className="text-indigo-600"/> 素材创意 DNA</h3>

             <div className="grid grid-cols-2 gap-4 mb-6">
                 <div className="bg-gray-50 p-3 rounded-lg">
                    <div className="text-xs text-gray-500">平均衰退周期</div>
                    <div className="font-semibold text-gray-900">{client.creativeStats?.lifecycleDays || '-'} 天</div>
                 </div>
                 <div className="bg-gray-50 p-3 rounded-lg">
                    <div className="text-xs text-gray-500">拒审率</div>
                    <div className="font-semibold text-gray-900">{client.creativeStats?.rejectionRate || 0}%</div>
                 </div>
             </div>

             <div className="mb-4">
                 <div className="text-sm text-gray-600 mb-2">Top 跑量素材</div>
                 <div className="space-y-3">
                    {client.creativeStats?.topCreatives.map(c => (
                        <div key={c.id} className="flex items-center gap-3 p-2 border border-gray-100 rounded-lg hover:bg-gray-50">
                            <img src={c.url} className="w-16 h-10 object-cover rounded bg-gray-200" alt={c.name}/>
                            <div className="flex-1">
                                <div className="text-sm font-medium truncate">{c.name}</div>
                                <div className="text-xs text-gray-500 capitalize">{c.type} • CTR {c.ctr}%</div>
                            </div>
                        </div>
                    ))}
                    {!client.creativeStats && <div className="text-gray-400 text-sm">暂无数据</div>}
                 </div>
             </div>

             <div>
                <div className="text-sm text-gray-600 mb-2">偏好标签</div>
                <div className="flex flex-wrap gap-2">
                    {client.creativeStats?.tags.map(tag => (
                        <span key={tag} className="px-2 py-1 bg-violet-50 text-violet-700 text-xs rounded border border-violet-100">{tag}</span>
                    ))}
                </div>
             </div>
        </div>

        {/* App Product Health */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Smartphone size={18} className="text-indigo-600"/> 应用产品健康度</h3>

             <div className="flex items-center gap-4 mb-6">
                 <div className="text-4xl font-bold text-gray-900">{client.appHealth?.storeRating || 'N/A'}</div>
                 <div className="flex flex-col">
                    <div className="flex text-yellow-400">★★★★☆</div>
                    <span className="text-xs text-gray-500">应用商店评分</span>
                 </div>
             </div>

             <div className="space-y-4">
                 <div>
                    <div className="flex justify-between text-sm mb-1">
                        <span className="text-gray-600">崩溃率 (Crash Rate)</span>
                        <span className={`${(client.appHealth?.crashRate || 0) > 1 ? 'text-red-500' : 'text-green-600'}`}>{client.appHealth?.crashRate || 0}%</span>
                    </div>
                    <div className="w-full bg-gray-100 rounded-full h-2">
                        <div className="bg-gray-400 h-2 rounded-full" style={{width: `${(client.appHealth?.crashRate || 0) * 20}%`}}></div>
                    </div>
                 </div>

                 <div>
                    <div className="flex justify-between text-sm mb-1">
                        <span className="text-gray-600">包体大小</span>
                        <span>{client.appHealth?.packageSizeMB || '-'} MB</span>
                    </div>
                    <div className="text-xs text-gray-400">包体过大可能会降低 15% 的转化率</div>
                 </div>

                 <div className="pt-4 border-t border-gray-100">
                    <span className="text-sm font-medium text-gray-700 block mb-2">高频负面舆情</span>
                    <div className="flex gap-2">
                        {client.appHealth?.negativeSentimentKeywords.map(k => (
                             <span key={k} className="px-2 py-1 bg-red-50 text-red-600 text-xs rounded border border-red-100">{k}</span>
                        ))}
                    </div>
                 </div>
             </div>
        </div>
      </div>
    );
  };

  const renderAudienceGrowthTab = () => {
    if (!client.audienceData) {
        return renderEmptyState("暂无人群或增长机会数据");
    }
    return (
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Audience Profile */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Users size={18} className="text-indigo-600"/> 人群画像与渗透</h3>

             <div className="mb-6">
                 <div className="flex justify-between items-end mb-2">
                     <span className="text-sm text-gray-600">核心人群渗透率</span>
                     <span className="text-xl font-bold text-indigo-600">{client.audienceData?.penetrationRate || 0}%</span>
                 </div>
                 <div className="w-full bg-gray-100 rounded-full h-3">
                     <div className="bg-indigo-600 h-3 rounded-full" style={{width: `${client.audienceData?.penetrationRate || 0}%`}}></div>
                 </div>
                 <div className="text-xs text-gray-500 mt-2 text-right">仍有大量蓝海人群未触达</div>
             </div>

             <div className="mb-6">
                 <div className="text-sm text-gray-600 mb-3">已获客特征</div>
                 <div className="space-y-2">
                     {client.audienceData?.demographics.map((demo, i) => (
                         <div key={i} className="flex items-center text-sm">
                             <span className="w-20 text-gray-500">{demo.label}</span>
                             <div className="flex-1 h-2 bg-gray-100 rounded-full mx-2">
                                 <div className="h-2 bg-blue-400 rounded-full" style={{width: `${demo.value}%`}}></div>
                             </div>
                             <span className="text-gray-700 font-medium">{demo.value}%</span>
                         </div>
                     ))}
                     {!client.audienceData && <div className="text-gray-400 text-sm">暂无数据</div>}
                 </div>
             </div>

             <div className="p-3 bg-gray-50 rounded-lg flex justify-between items-center">
                 <span className="text-sm text-gray-600">竞品人群重合度</span>
                 <span className="font-bold text-gray-800">{client.audienceData?.competitorOverlap || 0}%</span>
             </div>
          </div>

          {/* Growth Opportunity */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Zap size={18} className="text-indigo-600"/> 增长机会诊断</h3>

             <div className="space-y-4">
                 <div className="border-l-4 border-yellow-400 pl-4 py-1">
                     <h4 className="text-sm font-bold text-gray-800 mb-2">推荐蓝海词包</h4>
                     <ul className="space-y-1">
                         {client.growthOpp?.recommendedKeywords.map((k, i) => (
                             <li key={i} className="text-sm flex justify-between">
                                 <span className="text-gray-600">{k.keyword}</span>
                                 <span className="text-xs bg-green-100 text-green-700 px-2 rounded">竞争: {k.competition}</span>
                             </li>
                         ))}
                     </ul>
                 </div>

                 <div className="border-l-4 border-blue-400 pl-4 py-1">
                     <h4 className="text-sm font-bold text-gray-800 mb-2">未投版位机会</h4>
                      <ul className="space-y-1">
                         {client.growthOpp?.missedPlacements.map((p, i) => (
                             <li key={i} className="text-sm flex justify-between">
                                 <span className="text-gray-600">{p.name}</span>
                                 <span className="text-xs font-bold text-blue-600">预估提升 {p.potentialLift}</span>
                             </li>
                         ))}
                     </ul>
                 </div>

                 <div className="mt-4 pt-4 border-t border-gray-100">
                     <h4 className="text-xs text-gray-500 uppercase font-semibold mb-2">行业趋势对标</h4>
                     <div className="flex gap-2 flex-wrap">
                         {client.growthOpp?.industryTrends.map((t, i) => (
                             <span key={i} className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-full flex items-center gap-1">
                                 <TrendingUp size={10} /> {t}
                             </span>
                         ))}
                     </div>
                 </div>
             </div>
          </div>
      </div>
    );
  };

  const renderChurnTab = () => {
      // Consolidated view: Show detailed analysis if CHURN stage, or Risk Analysis if Active/Prospect

      const isChurned = client.stage === ClientStage.CHURN;

      return (
        <div className="space-y-6">
            {/* Main Risk/Churn Status Card */}
            <div className={`rounded-xl p-6 flex flex-col md:flex-row gap-6 items-start border ${isChurned ? 'bg-red-50 border-red-100' : 'bg-orange-50 border-orange-100'}`}>
                <div className={`p-3 bg-white rounded-full shadow-sm ${isChurned ? 'text-red-500' : 'text-orange-500'}`}>
                   <AlertTriangle size={32} />
                </div>
                <div className="flex-1">
                    <h3 className={`text-xl font-bold mb-2 ${isChurned ? 'text-red-800' : 'text-orange-800'}`}>
                        {isChurned ? '已流失客户' : '流失风险预测'} 
                        <span className="ml-2 text-sm opacity-80">风险评分: {client.riskScore || (isChurned ? 90 : 25)}/100</span>
                    </h3>

                    {isChurned ? (
                        <>
                            <p className="text-red-700 mb-4">
                                该广告主自 {client.lastActiveDate} 起停止投放。 
                                主要原因: <strong>{client.churnReason}</strong>。
                            </p>
                            <div className="bg-white/60 rounded-lg p-4">
                                <h4 className="font-semibold text-red-800 mb-2">建议挽回措施:</h4>
                                <ul className="list-disc list-inside space-y-1 text-sm text-red-800">
                                {client.retentionPlan?.map((plan, i) => (
                                    <li key={i}>{plan}</li>
                                ))}
                                </ul>
                            </div>
                        </>
                    ) : (
                        <>
                             <p className="text-orange-800 mb-4">
                                当前客户状态正常，但需持续关注以下风险指标。欺诈评分: <strong>{client.riskProfile?.fraudScore || 0}</strong> (分数越低越好)。
                            </p>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="bg-white/60 rounded-lg p-3">
                                    <div className="text-xs text-orange-800 mb-1">历史违规</div>
                                    <div className="font-bold text-orange-900">{client.riskProfile?.violationCount || 0} 次</div>
                                </div>
                                <div className="bg-white/60 rounded-lg p-3">
                                    <div className="text-xs text-orange-800 mb-1">钱包余额健康度</div>
                                    <div className="font-bold text-orange-900">{client.financialHealth?.walletRunwayDays || 0} 天</div>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            </div>

            {/* Analysis Charts - Displayed for both but context differs */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 mb-4">
                        {isChurned ? '流失前消耗趋势' : '近期消耗稳定性'}
                    </h3>
                    <TrendChart 
                        data={client.spendTrend || []} 
                        dataKey="value" 
                        color={isChurned ? "#ef4444" : "#f97316"} 
                    />
                </div>

                {/* Financial Health / Additional Risk Details */}
                 <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-6">
                        <Wallet size={18} className="text-gray-500"/> 财务健康诊断
                    </h3>
                     <div className="space-y-6">
                        <div className="flex justify-between items-center">
                            <span className="text-gray-600 text-sm">账户模式</span>
                            <span className="px-3 py-1 bg-blue-50 text-blue-700 text-xs rounded-full font-medium">
                                {client.financialHealth?.paymentMode || 'Prepay'}
                            </span>
                        </div>
                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-gray-600 text-sm">余额预计支撑天数</span>
                                <span className="text-xl font-bold text-gray-900">{client.financialHealth?.walletRunwayDays || 0} 天</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2">
                                <div className={`h-2 rounded-full ${(client.financialHealth?.walletRunwayDays || 0) < 7 ? 'bg-red-500' : 'bg-green-500'}`} 
                                     style={{width: `${Math.min((client.financialHealth?.walletRunwayDays || 0) * 5, 100)}%`}}></div>
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-100">
                             <div>
                                <div className="text-xs text-gray-500 mb-1">退款率</div>
                                <div className="font-medium text-gray-900">{client.financialHealth?.refundRate || 0}%</div>
                             </div>
                             <div>
                                <div className="text-xs text-gray-500 mb-1">逾期记录</div>
                                <div className="font-medium text-gray-900">{client.financialHealth?.overdueHistory || 0} 次</div>
                             </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
      );
  };

  return (
    <div className="max-w-7xl mx-auto pb-12">
      {renderHeader()}

      {/* Insight Section - Always Visible if generated */}
      <div className="mb-8">
        {!insight ? (
          <button 
            onClick={handleGenerateInsight}
            disabled={loadingInsight}
            className="flex items-center gap-2 bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-5 py-3 rounded-lg shadow-md hover:shadow-lg transition-all disabled:opacity-70"
          >
            {loadingInsight ? (
               <>正在生成 AI 分析...</>
            ) : (
               <><Sparkles size={18} /> 生成 AI 战略洞察</>
            )}
          </button>
        ) : (
          <div className="bg-gradient-to-r from-violet-50 to-indigo-50 border border-indigo-100 rounded-xl p-6 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10 text-indigo-900">
                <BrainCircuit size={120} />
             </div>
             <h3 className="text-lg font-bold text-indigo-900 mb-3 flex items-center gap-2">
                <Sparkles size={18} className="text-indigo-600"/> AI 战略分析
             </h3>
             <p className="text-indigo-800 font-medium mb-4">{insight.summary}</p>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">行动建议</h4>
                    <ul className="space-y-2">
                        {insight.actionItems.map((item, i) => (
                            <li key={i} className="flex items-start gap-2 text-sm text-indigo-900">
                                <span className="mt-1 w-1.5 h-1.5 bg-indigo-500 rounded-full flex-shrink-0"></span>
                                {item}
                            </li>
                        ))}
                    </ul>
                </div>
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">AI 预测</h4>
                    <p className="text-sm text-indigo-900 italic">"{insight.prediction}"</p>
                </div>
             </div>
             <button onClick={() => setInsight(null)} className="mt-4 text-xs text-indigo-500 hover:text-indigo-700 underline">刷新分析</button>
          </div>
        )}
      </div>

      {/* Unified Tab Navigation */}
      <div>
        <div className="flex border-b border-gray-200 mb-6 overflow-x-auto scrollbar-hide">
            {[
                { id: 'prospect', label: '拓展进度', icon: <Briefcase size={16}/> },
                { id: 'performance', label: '投放分析', icon: <BarChart2 size={16}/> },
                { id: 'creative', label: '素材与产品', icon: <Sparkles size={16}/> },
                { id: 'audience', label: '人群与增长', icon: <Users size={16}/> },
                { id: 'churn', label: '流失预测', icon: <AlertTriangle size={16}/> },
            ].map(tab => (
                 <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`flex items-center gap-2 px-5 py-3 text-sm font-medium whitespace-nowrap border-b-2 transition-colors
                        ${activeTab === tab.id 
                            ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' 
                            : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                        }`}
                >
                    {tab.icon}
                    {tab.label}
                </button>
            ))}
        </div>

        {/* Tab Content */}
        <div className="min-h-[400px]">
            {activeTab === 'prospect' && renderProspectTab()}
            {activeTab === 'performance' && renderPerformanceTab()}
            {activeTab === 'creative' && renderCreativeProductTab()}
            {activeTab === 'audience' && renderAudienceGrowthTab()}
            {activeTab === 'churn' && renderChurnTab()}
        </div>
      </div>
    </div>
  );
};
